const incoming = items[0]?.json ?? {};
const sessionId = String(
  incoming.sessionId ??
  incoming.chatSessionId ??
  incoming.session_id ??
  incoming.userId ??
  'default-session'
);
const chatInput = String(
  incoming.chatInput ??
  incoming.text ??
  incoming.message ??
  ''
).trim();

const existingSession = sessions[sessionId] ?? {
  phase: 'welcome',
  authenticated: false,
  authAttempts: 0,
  userId: null,
  name: null,
  pendingIntents: [],
  intents: [],
  processedIntents: []
};

const mockUsers = {
  '5673': { name: 'Devin', pin: '1234' },
  '2468': { name: 'Ava', pin: '4321' },
  '1357': { name: 'Sam', pin: '2468' }
};

const hasId = /\b(?:user\s*id|id)\D*(\d{3,})\b/i.test(chatInput);
const hasPin = /\bpin\D*(\d{4})\b/i.test(chatInput);
const looksLikeCredentials = hasId && hasPin;

return [{
  json: {
    ...incoming,
    sessionId,
    chatInput,
    session: existingSession,
    looksLikeCredentials,
    mockUsers,
    text: incoming.text ?? ''
  }
