const sessions = staticData.multiIntentAssistantSessions ?? (staticData.multiIntentAssistantSessions = {});
const data = items[0].json;
const { sessionId, session, chatInput, mockUsers, skipAuth } = data;

if (skipAuth) {
  return [{ json: { ...data, authValidated: false, shouldSaveUser: false } }];
}

const idMatch = chatInput.match(/\b(?:user\s*id|id)\D*(\d{3,})\b/i);
const pinMatch = chatInput.match(/\bpin\D*(\d{4})\b/i);
if (!idMatch || !pinMatch) {
  const updatedSession = { ...session, phase: 'awaiting_auth', authAttempts: session.authAttempts ?? 0 };
  sessions[sessionId] = updatedSession;
  return [{ json: { ...data, session: updatedSession, authValidated: false, shouldSaveUser: false, text: 'Please send both your user ID and a 4-digit PIN in one message. Example: user id 5673 and pin 1234.' } }];
}

const userId = idMatch[1];
const pin = pinMatch[1];
const user = mockUsers[userId];
const isValid = Boolean(user && user.pin === pin);
if (!isValid) {
  const updatedSession = { ...session, phase: 'awaiting_auth', authAttempts: (session.authAttempts ?? 0) + 1 };
  sessions[sessionId] = updatedSession;
  return [{ json: { ...data, session: updatedSession, authValidated: false, shouldSaveUser: false, attemptedUserId: userId, text: 'Authentication failed. Please re-enter your user ID and 4-digit PIN.' } }];
}

return [{ json: { ...data, authValidated: true, shouldSaveUser: true, authenticatedUserId: userId, authenticatedName: user.name, text: 'Authentication successful.' } }];

