function buildIntentRequest(type, text) {
  const original = String(text ?? '').trim();
  const upperCodes = [...original.toUpperCase().matchAll(/\b(?:USD|EUR|GBP|INR|AUD|CAD|JPY|AED|CHF|SGD)\b/g)].map((match) => match[0]);

  if (type === 'currency_converter') {
    const pair = upperCodes.length >= 2 ? upperCodes[0] + ' to ' + upperCodes[1] : 'currency conversion';
    const amountMatch = original.match(/\b(\d+(?:\.\d+)?)\s*(USD|EUR|GBP|INR|AUD|CAD|JPY|AED|CHF|SGD)\b/i);
    const amountPrefix = amountMatch ? amountMatch[1] + ' ' : '';
    const datePart = /\byesterday\b/i.test(original) ? ' for yesterday' : (/\btoday\b/i.test(original) ? ' for today' : '');
    return amountPrefix + pair + ' conversion' + datePart;
  }

  if (type === 'natural_language_datetime') {
    const comingWeekday = original.match(/\b(?:coming|next)\s+(sunday|monday|tuesday|wednesday|thursday|friday|saturday)\b/i);
    if (comingWeekday) return 'date on the coming ' + comingWeekday[1];

    const relative = original.match(/\b(?:today|tomorrow|yesterday)\b/i);
    if (relative) return 'date ' + relative[0].toLowerCase();

    const hours = original.match(/\b\d+\s+hours?\s+from\s+now\b/i);
    if (hours) return hours[0];

    return 'requested date or time';
  }

  return original;
}

function parseIntents(message) {
  const text = String(message ?? '').trim();
  if (!text) return [];
  const lowered = text.toLowerCase();
  const intents = [];

  const currencyMatch = lowered.match(/\b(?:usd|eur|gbp|inr|aud|cad|jpy|aed|chf|sgd)\b.*\b(?:to|in)\b.*\b(?:usd|eur|gbp|inr|aud|cad|jpy|aed|chf|sgd)\b|\b(?:convert|conversion|exchange rate|currency|rate)\b/);
  if (currencyMatch) {
    intents.push({ type: 'currency_converter', label: 'currency conversion', request: buildIntentRequest('currency_converter', text), sourceMessage: text, order: currencyMatch.index ?? 0 });
  }

  const explicitDateTimeRequest = /\b(?:date|time)\b|\bwhat(?:'s| is)?\s+the\s+(?:date|time)\b|\bwhat\s+day\b|\bcoming\s+(?:monday|tuesday|wednesday|thursday|friday|saturday|sunday)\b|\bdate\s+on\b|\btime\s+on\b|\b\d+\s+(?:hours?|days?|weeks?|months?|years?)\s+from\s+now\b|\bnow\b/i;
  const weakTemporalOnly = /\b(?:today|tomorrow|yesterday|next\s+(?:monday|tuesday|wednesday|thursday|friday|saturday|sunday)|coming\s+(?:monday|tuesday|wednesday|thursday|friday|saturday|sunday))\b/i;
  const shouldAddDateTime = explicitDateTimeRequest.test(text) || (!currencyMatch && weakTemporalOnly.test(text));
  const datetimeMatch = shouldAddDateTime ? lowered.match(/\b(?:date|time|today|tomorrow|yesterday|next|coming|monday|tuesday|wednesday|thursday|friday|saturday|sunday|hour|hours|minute|minutes|day|days|week|weeks|month|months|year|years|now)\b/) : null;
  if (datetimeMatch) {
    intents.push({ type: 'natural_language_datetime', label: 'natural language date and time', request: buildIntentRequest('natural_language_datetime', text), sourceMessage: text, order: datetimeMatch.index ?? 9999 });
  }

  intents.sort((a, b) => a.order - b.order);
  const seen = new Set();
  return intents.filter((intent) => {
    if (seen.has(intent.type)) return false;
    seen.add(intent.type);
    return true;
  }).map(({ order, ...intent }) => intent);
}

function classifyUnsupported(message) {
  return /\b(?:weather|joke|email|calendar|alarm|reminder|news|book|flight|hotel|pizza|translate|summary|summarize|stock|music|song|play)\b/i.test(message);
